{
  "name": "Calculadora de Ejes de Pavimento",
  "description": "Herramienta de ingeniería civil para la conversión de composición vehicular a ejes equivalentes según NOM-012-SCT-2-2017."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneralData {
  projectName: string;
  section: string;
  roadType: 'ET_A' | 'B' | 'C' | 'D';
  tdpa: number;
  pvc: number;
  lanes: '1' | '2' | '3+';
}

export type VehicleName = 
  | "A2" | "B2" | "B36" | "B38" | "B4" 
  | "C2" | "C36" | "C38" | "C2R2" | "C3R2"
  | "C3R3" | "C2R3" | "T2S1" | "T2S2" | "T3S2" 
  | "T3S3" | "T2S3" | "T3S1" | "T2S1R2" | "T2S1R3"
  | "T2S2R2" | "T3S1R2" | "T3S1R3" | "T3S2R2" | "T3S2R4" 
  | "T3S2R3" | "T3S3S2" | "T2S2S2" | "T3S2S2";

// The composition data is simply an array of 29 numbers (percentages)
// indexed consistently with the NOMBRES array.
export type CompositionData = number[]; 

export interface RowResult {
  no: number;
  tipo: string;
  estado: string;
  llantas: number;
  etya: number;
  b: number;
  c: number;
  d: number;
  result: number;
}

import React from 'react';
import { NavLink } from 'react-router-dom';

const Navbar: React.FC = () => {
  const getLinkClass = ({ isActive }: { isActive: boolean }) => 
    `flex items-center gap-2 px-4 py-2 rounded-md transition-colors duration-200 ${
      isActive 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' 
        : 'text-slate-300 hover:bg-slate-800 hover:text-white'
    }`;

  return (
    <nav className="bg-slate-900 border-b border-slate-800 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16 overflow-x-auto">
          <div className="flex items-center gap-2 md:gap-4">
            <NavLink to="/" className={getLinkClass}>
              <i className="fas fa-home"></i> 
              <span className="hidden sm:inline">Inicio</span>
            </NavLink>
            <NavLink to="/datos" className={getLinkClass}>
              <i className="fas fa-file-invoice"></i> 
              <span className="whitespace-nowrap">Datos Generales</span>
            </NavLink>
            <NavLink to="/composicion" className={getLinkClass}>
              <i className="fas fa-calculator"></i> 
              <span className="whitespace-nowrap">Composición</span>
            </NavLink>
            <NavLink to="/ejes" className={getLinkClass}>
              <i className="fas fa-car-side"></i> 
              <span className="whitespace-nowrap">Ejes 1er. Año</span>
            </NavLink>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
