export default App;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { GeneralData } from '../types';
import { DEFAULT_GENERAL_DATA } from '../constants';

const GeneralDataPage: React.FC = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('datosGeneralesData');
    if (saved) {
      try {
        setFormData(JSON.parse(saved));
      } catch (e) {
        console.error("Error loading general data", e);
      }
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) : value
    }));
    setIsSaved(false);
  };

  const handleRadioChange = (name: keyof GeneralData, value: string) => {
    setFormData(prev => ({ ...prev, [name]: value }));
    setIsSaved(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    localStorage.setItem('datosGeneralesData', JSON.stringify(formData));
    setIsSaved(true);

    // Auto-hide success message
    setTimeout(() => setIsSaved(false), 3000);
  };

  const InputClass = "w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors";
  const LabelClass = "block text-sm font-semibold text-slate-400 mb-1";

  return (
    <div className="max-w-3xl mx-auto px-4 py-8">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-white mb-2">Datos Generales</h1>
        <p className="text-slate-400">Parámetros fundamentales para el cálculo de ejes.</p>
      </header>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Section 1: Project Info */}
        <div className="bg-slate-800/50 p-6 rounded-xl border border-slate-700">
          <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
            <i className="fas fa-road text-orange-500"></i> Información del Camino
          </h3>

          <div className="grid gap-4">
            <div>
              <label className={LabelClass}>Nombre del Proyecto</label>
              <input
                type="text"
                name="projectName"
                value={formData.projectName}
                onChange={handleChange}
                className={InputClass}
                placeholder="Ej. Carretera Federal 57"
              />
            </div>
            <div>
              <label className={LabelClass}>Tramo</label>
              <input
                type="text"
                name="section"
                value={formData.section}
                onChange={handleChange}
                className={InputClass}
                placeholder="Ej. Km 20+000 - Km 50+000"
              />
            </div>

            <div>
              <label className={LabelClass}>Tipo de Camino</label>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mt-2">
                {[
                    { val: 'ET_A', label: 'Tipo ET / A' },
                    { val: 'B', label: 'Tipo B' },
                    { val: 'C', label: 'Tipo C' },
                    { val: 'D', label: 'Tipo D' }
                ].map((opt) => (
                  <label 
                    key={opt.val} 
                    className={`cursor-pointer flex flex-col items-center justify-center p-3 rounded border transition-all ${
                        formData.roadType === opt.val 
                        ? 'bg-blue-600/20 border-blue-500 text-blue-400' 
                        : 'bg-slate-900 border-slate-700 hover:bg-slate-800'
                    }`}
                  >
                    <input
                      type="radio"
                      name="roadType"
                      value={opt.val}
                      checked={formData.roadType === opt.val}
                      onChange={() => handleRadioChange('roadType', opt.val)}
                      className="hidden"
                    />
                    <span className="font-medium text-sm text-center">{opt.label}</span>
                  </label>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Section 2: Design Params */}
        <div className="bg-slate-800/50 p-6 rounded-xl border border-slate-700">
          <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
            <i className="fas fa-sliders-h text-blue-500"></i> Parámetros de Diseño
          </h3>

          <div className="grid sm:grid-cols-2 gap-6">
            <div>
              <label className={LabelClass}>Tránsito Diario Promedio Anual (TDPA)</label>
              <input
                type="number"
                name="tdpa"
                value={formData.tdpa}
                onChange={handleChange}
                className={InputClass}
                min="0"
              />
            </div>
            <div>
              <label className={LabelClass}>% Vehículos Cargados (Pvc)</label>
              <input
                type="number"
                name="pvc"
                value={formData.pvc}
                onChange={handleChange}
                className={InputClass}
                min="0"
                max="100"
              />
            </div>
          </div>

          <div className="mt-6">
            <label className={LabelClass}>Número de Carriles (por sentido)</label>
            <div className="flex gap-4 mt-2">
              {[
                  { val: '1', label: '1 Carril' },
                  { val: '2', label: '2 Carriles' },
                  { val: '3+', label: '3 o más' }
              ].map((opt) => (
                <label 
                    key={opt.val}
                    className={`flex-1 cursor-pointer flex items-center justify-center p-3 rounded border transition-all ${
                        formData.lanes === opt.val 
                        ? 'bg-emerald-600/20 border-emerald-500 text-emerald-400' 
                        : 'bg-slate-900 border-slate-700 hover:bg-slate-800'
                    }`}
                >
                    <input
                        type="radio"
                        name="lanes"
                        value={opt.val}
                        checked={formData.lanes === opt.val}
                        onChange={() => handleRadioChange('lanes', opt.val)}
                        className="hidden"
                    />
                    <i className="fas fa-road mr-2"></i>
                    <span className="font-medium">{opt.label}</span>
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* Actions */}
        <div className="flex flex-col sm:flex-row gap-4 pt-4">
            <button
                type="submit"
                className="flex-1 bg-orange-600 hover:bg-orange-700 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2"
            >
                <i className="fas fa-save"></i>
                Guardar Datos
            </button>
            <button
                type="button"
                onClick={() => navigate('/composicion')}
                className="flex-1 bg-slate-700 hover:bg-slate-600 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2"
            >
                Siguiente: Composición <i className="fas fa-arrow-right"></i>
            </button>
        </div>

        {/* Success Feedback */}
        {isSaved && (
            <div className="fixed bottom-6 right-6 bg-green-500 text-white px-6 py-3 rounded-lg shadow-lg shadow-green-900/50 flex items-center gap-3 animate-bounce">
                <i className="fas fa-check-circle"></i> Datos guardados correctamente
            </div>
        )}

      </form>
    </div>
  );
};

export default GeneralDataPage;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { VEHICLE_NAMES, DEFAULT_COMPOSITION } from '../constants';
import { CompositionData } from '../types';

const CompositionPage: React.FC = () => {
  const navigate = useNavigate();
  const [values, setValues] = useState<CompositionData>(DEFAULT_COMPOSITION);

  // Load initial data
  useEffect(() => {
    const saved = localStorage.getItem('compVehData');
    if (saved) {
      try {
        setValues(JSON.parse(saved));
      } catch (e) {
        console.error("Error loading composition data", e);
      }
    }
  }, []);

  // Calculate sum automatically
  const total = useMemo(() => {
    return values.reduce((acc, curr) => acc + (Number(curr) || 0), 0);
  }, [values]);

  const isValid = Math.abs(total - 100.0) < 0.01;

  const handleInputChange = (index: number, valStr: string) => {
    const newVal = parseFloat(valStr);
    const newValues = [...values];
    newValues[index] = isNaN(newVal) ? 0 : newVal;
    setValues(newValues);
  };

  const handleSave = () => {
    if (!isValid) {
      alert("La sumatoria debe ser exactamente 100.00% para continuar.");
      return;
    }
    localStorage.setItem('compVehData', JSON.stringify(values));
    navigate('/ejes');
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-32">
      <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
            <h1 className="text-3xl font-bold text-white mb-2">Composición Vehicular</h1>
            <p className="text-slate-400">Ingrese el porcentaje (%) para cada tipo de vehículo según NOM-012.</p>
        </div>

        {/* Sticky Total Indicator (Mobile friendly) */}
        <div className={`
            px-6 py-3 rounded-lg font-mono text-xl font-bold border flex items-center gap-3 shadow-lg
            ${isValid 
                ? 'bg-emerald-900/40 border-emerald-500 text-emerald-400' 
                : 'bg-red-900/40 border-red-500 text-red-400'}
        `}>
            <span>Total:</span>
            <span>{total.toFixed(2)}%</span>
            {isValid ? <i className="fas fa-check"></i> : <i className="fas fa-exclamation-triangle"></i>}
        </div>
      </header>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {VEHICLE_NAMES.map((name, index) => (
            <div key={name} className="bg-slate-800 border border-slate-700 rounded-lg p-4 flex items-center gap-4 hover:border-slate-500 transition-colors">
                <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center font-bold text-slate-400 text-sm shrink-0">
                    {index + 1}
                </div>

                {/* Placeholder for Vehicle Image - Using a stylized box/icon since we don't have the pngs */}
                <div className="w-16 h-10 bg-slate-900 rounded border border-slate-700 flex items-center justify-center shrink-0">
                   <span className="text-xs font-bold text-slate-500">{name}</span>
                </div>

                <div className="flex-grow">
                    <label className="block text-xs text-slate-400 mb-1">{name}</label>
                    <div className="relative">
                        <input
                            type="number"
                            step="0.01"
                            value={values[index]}
                            onFocus={(e) => e.target.select()}
                            onChange={(e) => handleInputChange(index, e.target.value)}
                            className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1 text-right text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono"
                        />
                        <span className="absolute right-8 top-1.5 text-slate-500 text-xs pointer-events-none">%</span>
                    </div>
                </div>
            </div>
        ))}
      </div>

      {/* Floating Action Bar */}
      <div className="fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur-md border-t border-slate-800 p-4 z-40">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
            <div className="hidden sm:block text-slate-400 text-sm">
                {isValid 
                    ? "La composición es válida. Puede continuar." 
                    : `Faltan ${(100 - total).toFixed(2)}% para completar el 100%.`}
            </div>
            <button 
                onClick={handleSave}
                disabled={!isValid}
                className={`
                    px-8 py-3 rounded-lg font-bold shadow-lg flex items-center gap-2 transition-all
                    ${isValid 
                        ? 'bg-blue-600 hover:bg-blue-500 text-white hover:shadow-blue-500/25 cursor-pointer' 
                        : 'bg-slate-700 text-slate-500 cursor-not-allowed'}
                `}
            >
                <i className="fas fa-save"></i>
                Guardar y Calcular Ejes
            </button>
        </div>
      </div>
    </div>
  );
};

export default CompositionPage;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData, RowResult, VehicleName } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';

const AxlePage: React.FC = () => {
    const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
    const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

    useEffect(() => {
        const savedGen = localStorage.getItem('datosGeneralesData');
        if (savedGen) setGenData(JSON.parse(savedGen));

        const savedComp = localStorage.getItem('compVehData');
        if (savedComp) setCompData(JSON.parse(savedComp));
    }, []);

    // Core Calculation Logic
    const results: RowResult[] = useMemo(() => {
        // Map composition array to an object { "A2": 85, "B2": 2, ... } for easy formula usage
        const compObj: Record<string, number> = {};
        VEHICLE_NAMES.forEach((name, idx) => {
            compObj[name] = compData[idx] || 0;
        });

        // Helper to safely get value
        const getVal = (key: string) => compObj[key] || 0;

        const Pvc = genData.pvc;
        const TDPA = genData.tdpa;

        let fcp = 0.5;
        if (genData.lanes === '2') fcp = 0.45;
        if (genData.lanes === '3+') fcp = 0.4;

        const TDPAcd = fcp * TDPA;
        const fvp = 0.0365 * Pvc * TDPAcd;
        const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

        // The formulas (Ported exactly from the original HTML logic)
        const formulas = [
            // 0
            () => 2 * getVal("A2") * (fvp + fvv),
            // 1
            () => (100 - getVal("A2") + getVal("B4")) * fvp,
            // 2
            () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
            // 3
            () => (
                2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3")
                + 3*getVal("T2S1R2") + 2*getVal("T2S1R3")
                + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3")
                + 2*getVal("T3S2R2") + getVal("T3S2R3")
            ) * fvp,
            // 4
            () => (getVal("T2S1") + getVal("T3S1")) * fvp,
            // 5
            () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
            // 6
            () => (
                getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38")
                + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3")
                + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1")
                + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2")
                + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3")
                + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")
            ) * fvv,
            // 7
            () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
            // 8
            () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
            // 9
            () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
            // 10
            () => (
                getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2")
                + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")
            ) * fvp,
            // 11
            () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
            // 12
            () => (
                getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")
            ) * fvp,
            // 13
            () => (
                getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2")
                + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2")
                + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3")
                + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")
            ) * fvv,
            // 14
            () => getVal("T3S3S2") * fvp,
            // 15
            () => (getVal("T3S3") + getVal("T2S3")) * fvp,
            // 16
            () => getVal("T3S3S2") * fvv
        ];

        return TABLE_STATIC_ROWS.map((staticRow, index) => {
            const calculatedVal = formulas[index] ? formulas[index]() : 0;
            return {
                no: staticRow[0],
                tipo: staticRow[1],
                estado: staticRow[2],
                llantas: staticRow[3],
                etya: staticRow[4],
                b: staticRow[5],
                c: staticRow[6],
                d: staticRow[7],
                result: calculatedVal
            };
        });

    }, [genData, compData]);

    const totalEjes = useMemo(() => results.reduce((sum, row) => sum + row.result, 0), [results]);

    const formatNumber = (num: number) => Math.round(num).toLocaleString('en-US');

    // Export Logic
    const exportCSV = () => {
        const headers = ["No.", "Tipo", "Estado", "Llantas", "ET y A", "B", "C", "D", "Ejes 1er Año"];
        const rows = results.map(r => [r.no, r.tipo, r.estado, r.llantas, r.etya, r.b, r.c, r.d, Math.round(r.result)]);

        const csvContent = "data:text/csv;charset=utf-8," 
            + headers.join(",") + "\n" 
            + rows.map(e => e.join(",")).join("\n");

        const link = document.createElement("a");
        link.setAttribute("href", encodeURI(csvContent));
        link.setAttribute("download", "ejes_1er_anio.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="max-w-7xl mx-auto px-4 py-8">
            <header className="mb-6">
