        const fvp = 0.0365 * Pvc * TDPAcd;
        const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

        // The formulas (Ported exactly from the original HTML logic)
        const formulas = [
            // 0
            () => 2 * getVal("A2") * (fvp + fvv),
