                + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")
            ) * fvv,
            // 7
            () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
            // 8
            () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
            // 9
            () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
            // 10
            () => (
                getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2")
                + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")
            ) * fvp,
            // 11
            () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
            // 12
            () => (
                getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")
            ) * fvp,
            // 13
