    `flex flex-col md:flex-row items-center justify-center gap-1 md:gap-2 px-3 md:px-4 py-2 rounded-md transition-colors duration-200 text-xs md:text-base flex-1 md:flex-none ${
      isActive 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' 
        : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`;

  return (
    <nav className="bg-slate-900 border-b border-slate-800 sticky top-0 z-50 shadow-md">
      <div className="max-w-7xl mx-auto px-2 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Logo / Título (Oculto en móviles muy pequeños para dar espacio al menú) */}
          <div className="hidden md:flex items-center font-bold text-slate-200 mr-4">
            <i className="fas fa-truck-moving text-blue-500 mr-2"></i>
            <span>Ingeniería Civil</span>
          </div>

          {/* Menú de navegación full width en móvil */}
          <div className="flex items-center justify-between w-full md:w-auto gap-1 md:gap-2">
            <NavLink to="/" className={getLinkClass}>
              <i className="fas fa-home text-sm md:text-lg"></i> 
              <span>Inicio</span>
            </NavLink>
            <NavLink to="/datos" className={getLinkClass}>
              <i className="fas fa-file-invoice text-sm md:text-lg"></i> 
              <span className="whitespace-nowrap">Datos</span>
            </NavLink>
            <NavLink to="/composicion" className={getLinkClass}>
              <i className="fas fa-calculator text-sm md:text-lg"></i> 
              <span>Comp.</span>
            </NavLink>
            <NavLink to="/ejes" className={getLinkClass}>
              <i className="fas fa-car-side text-sm md:text-lg"></i> 
              <span>Ejes</span>
            </NavLink>
            <NavLink to="/esals" className={getLinkClass}>
              <i className="fas fa-road text-sm md:text-lg"></i> 
              <span>ESALs</span>
            </NavLink>
          </div>
        </div>
      </div>
    </nav>
  );
};

