export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';

interface EsalRow {
  no: number;
  tipo: string;
  l2: number;
  lxKip: number;
  ejesAnio: number;
  fx: number;
  esalAnio: number;
}

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design
  const [sn, setSn] = useState<number>(3.0); // Structural Number
  const [pt, setPt] = useState<number>(2.5); // Terminal Serviceability

  // Data from previous steps
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

  useEffect(() => {
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData(JSON.parse(savedGen));

    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));
  }, []);

  // --- 1. RECALCULATE EJES (Same logic as AxlePage to ensure consistency) ---
  const ejesResults = useMemo(() => {
    const compObj: Record<string, number> = {};
    VEHICLE_NAMES.forEach((name, idx) => {
        compObj[name] = compData[idx] || 0;
    });
    const getVal = (key: string) => compObj[key] || 0;

    const Pvc = genData.pvc;
    const TDPA = genData.tdpa;
    let fcp = 0.5;
    if (genData.lanes === '2') fcp = 0.45;
    if (genData.lanes === '3+') fcp = 0.4;
    const TDPAcd = fcp * TDPA;
    const fvp = 0.0365 * Pvc * TDPAcd;
    const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

    const formulas = [
        () => 2 * getVal("A2") * (fvp + fvv),
        () => (100 - getVal("A2") + getVal("B4")) * fvp,
        () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
        () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
        () => (getVal("T2S1") + getVal("T3S1")) * fvp,
        () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
        () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
        () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
        () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
        () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
        () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
        () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
        () => getVal("T3S3S2") * fvp,
        () => (getVal("T3S3") + getVal("T2S3")) * fvp,
        () => getVal("T3S3S2") * fvv
    ];

    return TABLE_STATIC_ROWS.map((row, i) => formulas[i] ? formulas[i]() : 0);
  }, [genData, compData]);


  // --- 2. CALCULATE ESALS (The new logic) ---
  const esalRows: EsalRow[] = useMemo(() => {
    // Constants for AASHTO formulas
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt: Function of Terminal Serviceability
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18: Function of SN
    const beta18 = 0.4 + (1094 / pow(sn + 1, 5.19));

    return TABLE_STATIC_ROWS.map((staticRow, index) => {
        const rowNo = staticRow[0];
        const rowTipo = staticRow[1];

        // --- COL 3: L2 (Axle Code) ---
        let l2 = 1;
        if (rowTipo === "Tándem") l2 = 2;
        if (rowTipo === "Trídem") l2 = 3;

        // --- COL 4: Lx (Weight in Kips) ---
        // Select column based on road type from General Data
        // staticRow indices: 4=ET_A, 5=B, 6=C, 7=D
        let weightTon = 0;
        switch(genData.roadType) {
            case 'ET_A': weightTon = staticRow[4]; break;
            case 'B':    weightTon = staticRow[5]; break;
            case 'C':    weightTon = staticRow[6]; break;
            case 'D':    weightTon = staticRow[7]; break;
            default:     weightTon = staticRow[4];
        }
        const lxKip = weightTon * 2.20462; // Convert Tonnes to Kips

        // --- COL 6: Fx (Load Equivalency Factor) ---
        // Beta X calculation
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(sn + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // Fx Exponent calculation
        // 4.79 log(19) - 4.79 log(Lx + L2) + 4.33 Log(L2) + Gt/βx - Gt/β18
        // Note: log(19) comes from (18 + 1) for standard axle
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        // --- COL 5: Ejes 1er Año (Recalculated) ---
        const ejes = ejesResults[index] || 0;

        // --- COL 7: ESAL 1er Año ---
        const esal = fx * ejes;

        return {
            no: rowNo,
            tipo: rowTipo,
            l2,
            lxKip,
            ejesAnio: ejes,
            fx,
            esalAnio: esal
        };
    });
  }, [sn, pt, genData.roadType, ejesResults]);

  const totalESALs = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const exportCSV = () => {
    const headers = ["No.", "Tipo", "L2", "Lx(kip)", "Ejes 1er Año", "Fx", "ESAL 1er Año"];
    const rows = esalRows.map(r => [
        r.no, r.tipo, r.l2, r.lxKip.toFixed(2), Math.round(r.ejesAnio), r.fx.toFixed(4), r.esalAnio.toFixed(2)
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", "esals_calculo.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Cálculo de ESALs</h1>
        <p className="text-slate-400">Equivalent Single Axle Load (AASHTO 93)</p>
      </header>

      {/* Inputs Section */}
      <div className="bg-slate-800 border border-slate-700 rounded-xl p-6 mb-8 shadow-lg">
        <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
            <i className="fas fa-sliders-h text-blue-500"></i> Parámetros AASHTO
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
                <label className="block text-sm font-semibold text-slate-400 mb-1">
                    Número Estructural (SN)
                </label>
                <input 
                    type="number" 
                    step="0.01"
                    value={sn}
                    onChange={(e) => setSn(parseFloat(e.target.value) || 0)}
                    className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono text-lg"
                />
            </div>
            <div>
                <label className="block text-sm font-semibold text-slate-400 mb-1">
                    Serviciabilidad Final (Pt)
                </label>
                <input 
                    type="number" 
                    step="0.1"
                    min="1.5" max="3.0"
                    value={pt}
                    onChange={(e) => setPt(parseFloat(e.target.value) || 0)}
                    className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono text-lg"
                />
            </div>
        </div>
      </div>

      {/* Results Summary */}
      <div className="bg-gradient-to-r from-blue-900/50 to-slate-900 border border-blue-800 p-6 rounded-xl mb-8 flex flex-col md:flex-row justify-between items-center gap-4">
         <div>
            <div className="text-blue-400 text-sm font-bold uppercase tracking-wider">Total ESALs (1er Año)</div>
            <div className="text-slate-400 text-xs mt-1">Sumatoria de cargas equivalentes</div>
         </div>
         <div className="text-4xl font-mono font-bold text-white drop-shadow-lg">
            {formatNum(totalESALs, 2)}
         </div>
      </div>

      {/* Desktop Table */}
      <div className="hidden md:block bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left text-slate-400">
                <thead className="text-xs text-slate-200 uppercase bg-slate-800">
                    <tr>
                        <th className="px-4 py-3 text-center">No.</th>
                        <th className="px-4 py-3">Tipo</th>
                        <th className="px-4 py-3 text-center text-blue-300">L2</th>
                        <th className="px-4 py-3 text-right text-blue-300">Lx (kip)</th>
                        <th className="px-4 py-3 text-right">Ejes 1er Año</th>
                        <th className="px-4 py-3 text-right text-emerald-400">Fx</th>
                        <th className="px-4 py-3 text-right font-bold text-white bg-slate-700">ESAL 1er Año</th>
                    </tr>
                </thead>
                <tbody>
                    {esalRows.map((row, index) => (
                        <tr key={index} className="border-b border-slate-800 hover:bg-slate-800/50 transition-colors">
                            <td className="px-4 py-3 text-center">{row.no}</td>
                            <td className="px-4 py-3 font-medium text-slate-200">{row.tipo}</td>
                            <td className="px-4 py-3 text-center text-blue-200 font-mono">{row.l2}</td>
                            <td className="px-4 py-3 text-right font-mono">{formatNum(row.lxKip)}</td>
                            <td className="px-4 py-3 text-right">{Math.round(row.ejesAnio).toLocaleString()}</td>
                            <td className="px-4 py-3 text-right font-mono text-emerald-400">{formatNum(row.fx, 4)}</td>
                            <td className="px-4 py-3 text-right font-bold text-white bg-slate-800/30 font-mono">
                                {formatNum(row.esalAnio)}
                            </td>
                        </tr>
                    ))}
                    <tr className="bg-slate-800 font-bold text-white border-t-2 border-slate-600">
                        <td colSpan={6} className="px-4 py-4 text-right">TOTAL ESALs:</td>
                        <td className="px-4 py-4 text-right text-lg text-emerald-400 font-mono">
                            {formatNum(totalESALs)}
                        </td>
                    </tr>
                </tbody>
            </table>
        </div>
      </div>

      {/* Mobile Cards */}
      <div className="md:hidden space-y-4 mb-8">
        {esalRows.map((row) => (
            <div key={row.no} className="bg-slate-800 border border-slate-700 rounded-lg p-4 shadow-md">
                <div className="flex justify-between items-start mb-3 border-b border-slate-700 pb-2">
                    <div>
                        <span className="text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded mr-2">#{row.no}</span>
                        <span className="font-bold text-white">{row.tipo}</span>
                    </div>
                    <div className="text-right">
                        <div className="text-xs text-slate-400 mb-0.5">ESALs</div>
                        <div className="font-bold text-white font-mono">{formatNum(row.esalAnio)}</div>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4 text-sm mb-3">
                    <div>
                        <span className="text-slate-500 block text-xs">Carga (Lx)</span>
                        <span className="text-slate-200 font-mono">{formatNum(row.lxKip)} kip</span>
                    </div>
                     <div>
                        <span className="text-slate-500 block text-xs">Factor (Fx)</span>
                        <span className="text-emerald-400 font-mono">{formatNum(row.fx, 4)}</span>
                    </div>
                </div>
                 <div className="bg-slate-900/50 p-2 rounded flex justify-between text-xs">
                    <span className="text-slate-500">Ejes 1er Año:</span>
                    <span className="text-slate-300">{Math.round(row.ejesAnio).toLocaleString()}</span>
                </div>
            </div>
        ))}
      </div>

       <div className="flex flex-col sm:flex-row justify-end gap-4 fixed bottom-0 left-0 right-0 p-4 bg-slate-900/95 backdrop-blur border-t border-slate-800 z-40 md:static md:bg-transparent md:border-0 md:p-0">
            <button 
                onClick={exportCSV}
                className="flex-1 sm:flex-none bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-lg flex items-center justify-center gap-2 font-bold shadow-lg shadow-emerald-900/40 transition-all active:scale-95"
            >
                <i className="fas fa-file-csv"></i> <span className="md:inline">Exportar CSV</span>
            </button>
        </div>

    </div>
  );
};

export default EsalsPage;
